REPLACE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('126', '169', 'banda', 'banda-2931', '\n\n\n\n<p align=\"left\" ><strong>\n<font  size=\"5\" >E</font></strong><font  ><big><big><big><strong><font size=\"5\">XALTACI??N \nDEL TAMBOR Y EL BOMBO</font></strong></big></big></big></font><strong><font  size=\"5\" >&nbsp; \n&quot;AGRAM??N \n2004</font><font size=\"5\" >&quot;</font></strong></p> \n\n\n<table border=\"0\" cellpadding=\"0\" cellspacing=\"0\"  id=\"AutoNumber1\"   border>\n  <tr>\n    <td   valign=\"top\">\n<p align=\"center\">\n<embed   src=\"Images/tamborada_2004.swf\" align=\"left\"></td>\n    <td   colspan=\"2\">\n    <p align=\"center\"><strong >\n<font  size=\"6\" >Fotograf??as</font></strong></p>\n    <p align=\"center\">\n    <img border=\"0\" src=\"../../../images/cartero.gif\"   align=\"absbottom\"><p align=\"center\">\n    <b><font size=\"2\" ><a href=\"mailto:postmaster@moratalla-murcia.com?subject=Fotos tamborada Agram??n 2004\" >Si \n    quieres envi</a></font></b><b><font size=\"2\" ><a href=\"mailto:postmaster@moratalla-murcia.com?subject=Fotos tamborada Agram??n 2004\" >ar que ponga alguna de tus fotos env??amela</a>s</font></b></td>\n    <td  >\n    <p align=\"center\" >\n    <a target=\"_blank\" title=\"Monumento al Tambolinero en AGRAM??N - Inagurado el 19 de Marzo de 2004\" href=\"Images/tamborada2004/monumento101.jpg\">\n    <font >\n    <img border=\"0\" src=\"Images/tamborada2004/monumentoP01.jpg\" alt=\"Monumento al tambolinero\" align=\"left\"  ></font></a></p>\n    <p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"center\" >&nbsp;<p align=\"left\" >&nbsp;<p align=\"left\" >\n    <font ><b>Monumento al \n     \n    </b>\n    </font>\