REPLACE INTO `pages` (`id`, `category_id`, `title`, `slug`, `content`, `original_file`, `sort_order`, `created_at`) VALUES ('132', '29', 'F??ltol en Moratalla. 2?? Cadete', 'fultol-en-moratalla-2a-cadete-5336', '\n\n<table border=\"1\" cellpadding=\"0\" cellspacing=\"0\"  border  id=\"AutoNumber5\">\n  <tr>\n    <td ><b><font size=\"4\" >\n    <embed   src=\"../../../images/atras.swf\" align=\"left\"></font></b></td>\n  </tr>\n</table>\n\n<p><b><font size=\"4\" >CADETE FEMENINO<a href=\"images/cadete-femeninow.JPG\" target=\"_blank\"><img border=\"0\" src=\"images/cadete-femeninop.jpg\"  ></a></font></b></p>\n\n<table border=\"1\" cellpadding=\"0\" cellspacing=\"0\"  id=\"AutoNumber1\"  >\n  <tr>\n    <td  ></td>\n  </tr>\n  <tr>\n    <td >\n    <p >\n    <b><font  size=\"2\" >Con la colaboraci??n de \n    MIRIAM MART??NEZ RODR??GUEZ</font></b></p>\n    <p >\n    <font  size=\"1\" >No se visualizan los \n    resultados, por ser no ser relevantes, el equipo est?? actualmente en fase de \n    desarrollo, por lo que desde esta p??gina se les anima a continuar con ese \n    esp??ritu de sacrificio.</font></td>\n  </tr>\n  <tr>\n    <td >\n    <b><font  >FINAL DE TEMPORADA</font></b></td>\n  </tr>\n  <tr>\n    <td >\n    <p ><b>\n    <font  size=\"2\" >12</font></b><b><font  ><span lang=\"ES-TRAD\"><font size=\"2\">/03/2005 </font></span></font><span lang=\"ES-TRAD\">\n    <font   size=\"2\">- </font></span></b>\n    <font  size=\"2\"><b><span lang=\"ES-TRAD\"><font >\n    C.B. CEHEG??N&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; NOROESTE MORATALLA&nbsp;&nbsp;&nbsp;&nbsp; </font></span></b></font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" ><span lang=\"ES-TRAD\">??ltimo \n    partido de la 1?? fase y posiblemente de la temporada. Se volvi?? a perder, \n    pero deben estar contentas porque han recobrado la buena trayectoria que \n    llevaban. En el ??ltimo cuarto defendieron tan bien que solo recibieron 3 \n    puntos. ??Enhorabuena!. Ahora tienen que seguir trabajando y mejorar los \n    puntos d??biles para empezar a ganar partidos en la siguiente temporada.</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    <p align=\"left\" >\n    <font  ><b><font size=\"2\">05</font><span lang=\"ES-TRAD\"><font size=\"2\">/03/2005 \n    - </font></span></b></font><font  size=\"2\" ><b>\n    <span lang=\"ES-TRAD\">NOROESTE MORATALLA&nbsp;&nbsp;&nbsp;&nbsp; &nbsp;MARISTAS UCAM</span></b></font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" ><span lang=\"ES-TRAD\">Pen??ltimo \n    partido de la temporada regular. Nuestras chicas han perdido el buen rumbo \n    que llevaban. Con este equipo, en la primera vuelta y en su campo, \n    obtuvieron mejor resultado, recibiendo menos puntos y consiguiendo meter \n    m??s. Deben volver a centrarse, se las ve un poquito aceleradas y se \n    precipitan en ataque.</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    <p align=\"left\" >\n    <font ><font  size=\"2\"><b><span lang=\"ES-TRAD\">\n    26/02/2005 - </span></b></font><b><span lang=\"ES-TRAD\">\n    <font ></font><font size=\"2\"><font >JESUITINAS&nbsp;&nbsp;&nbsp; \n    &nbsp;&nbsp;NOROESTE MORATALLA&nbsp;</font>&nbsp;&nbsp;&nbsp; </font></span></b></font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" ><span lang=\"ES-TRAD\">En este \n    partido si que nuestras jugadoras han perdido un poco la buena l??nea que \n    llevaban. De todas formas no deben desanimarse porque est?? claro que est??n \n    realizando un gran trabajo.</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    <p ><font ><font  size=\"2\"><b>\n    12/02/2005</b></font><font ><b><span lang=\"ES-TRAD\" > \n    - </span></b></font></font><font  size=\"2\"><b>\n    <span lang=\"ES-TRAD\"><font >JAIRIS ALCANTARILLA&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; \n    NOROESTE MORATALLA&nbsp;&nbsp;</font>&nbsp;&nbsp; </span></b></font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" ><span lang=\"ES-TRAD\">Nuestras \n    chicas tuvieron que v??rselas ante un rival muy duro, que se est?? preparando \n    para los ???play-off??? y las someti?? a una presi??n en todo el campo casi todo \n    el partido. Esta es una defensa muy dif??cil de superar de las que nuestras \n    jugadoras se zafaron como pudieron. Pero siguieron en su l??nea de mejora, \n    por lo que hay que felicitarlas porque, a pesar de esa adversidad, han \n    conseguido all?? mejor resultado que el que obtuvieron en nuestro campo.</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    <p  align=\"left\"><b>\n    <font  size=\"2\" >05</font></b><font ><font  size=\"2\"><b>/02/2005</b></font><font ><b><span lang=\"ES-TRAD\" > \n    -</span></b></font></font><font  size=\"2\"><b><span lang=\"ES-TRAD\">\n    <font >NOROESTE MORATALLA&nbsp;&nbsp;&nbsp;&nbsp; C. B. MOLINA&nbsp;</font> </span>\n    </b></font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" ><span lang=\"ES-TRAD\">Han \n    mejorado notablemente el resultado del partido de ida. Este ha sido el \n    partido donde nuestras chicas han metido m??s puntos. ??Enhorabuena! Por la \n    continua evoluci??n.</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    <p  align=\"left\"><font >\n    <font  size=\"2\"><b>29/01/2005</b></font><font ><b><span lang=\"ES-TRAD\" > \n    -</span></b></font></font><font  size=\"2\"><b><span lang=\"ES-TRAD\">\n    <font >NOROESTE MORATALLA&nbsp;&nbsp;&nbsp;&nbsp; CARTAGENA</font></span></b></font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" ><span lang=\"ES-TRAD\">De nuevo, \n    han vuelto a mejorar el resultado del partido de ida, recibiendo menos \n    puntos. El trabajo que realizan durante la semana se va reflejando en el \n    campo y est?? claro que est??n en el buen camino. Enhorabuena.</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    <p ><font >\n    <font  size=\"2\"><b>22/01/2005</b></font><font ><b><span lang=\"ES-TRAD\" > \n    - NOROESTE MORATALLA&nbsp;&nbsp;&nbsp; SAN BUENAVENTURA</span></b></font></font></p>\n    <p class=\"MsoNormal\" >\n    <font  >\n    <span lang=\"ES-TRAD\" >Partido contra el l??der \n    invicto de la categor??a. Adem??s nos lleg?? informaci??n de que no son solo \n    jugadoras del colegio San Buenaventura, sino que tienen fichajes (si, aunque \n    sorprenda en estas categor??as). Es un equipo hecho claramente para ganar el \n    campeonato.</span></font></p>\n    <p class=\"MsoNormal\" >\n    <font  >\n    <span lang=\"ES-TRAD\" >Dicho esto, tambi??n decir que \n    hay que volver a felicitar a nuestras jugadoras, porque se supieron zafar \n    contra este rival tan fuerte y consiguieron mejor resultado que en el \n    partido de ida. Hay que volver a felicitarlas porque su evoluci??n sigue \n    siendo francamente buena. Enhorabuena.</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    <p ><b>\n    <font  size=\"2\" >15</font></b><font ><font  size=\"2\"><b>/01/2005</b></font><font ><b><span lang=\"ES-TRAD\" > \n    -</span></b></font></font><font  size=\"2\"><b><span lang=\"ES-TRAD\"> \n    INFANTE (de Murcia) &nbsp;&nbsp;&nbsp;&nbsp;NOROESTE MORATALLA</span></b></font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" ><span lang=\"ES-TRAD\">Nueva \n    derrota de las chicas ante uno de los equipos punteros de su categor??a. A \n    pesar de esto, deben tener claro que siguen en el buen camino y que deben \n    seguir trabajando en la misma l??nea, porque su esfuerzo en los \n    entrenamientos se est?? reflejando en el campo.</span></font></p>\n    <p class=\"MsoNormal\" >\n    <font  size=\"2\" ><span lang=\"ES-TRAD\">Tambi??n \n    hay que felicitarlas por su trabajo y entrega.</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    <p class=\"MsoNormal\" >\n    <b><font  size=\"2\" >09</font></b><font ><font  size=\"2\"><b>/01/2005</b></font><font ><b><span lang=\"ES-TRAD\" > \n    -  </span></b></font></font><font  size=\"2\"><b>\n    <span lang=\"ES-TRAD\" >JUGARON CONTRA C. B. \n    CEHEG??N</span></b></font></p>\n    <p class=\"MsoNormal\" >\n    <font ><font  size=\"2\"><span lang=\"ES-TRAD\">\n    Segundo partido del doble enfrentamiento producido este fin de semana. \n    Volvieron a perder, pero su evoluci??n sigue siendo evidente: sobre todo se \n    aprecia una notable mejora en la defensa, que en muchos momentos fue muy \n    agresiva y consiguieron robar muchos balones. Deben seguir en la misma l??nea \n    de mejora</span></font><span lang=\"ES-TRAD\" >.</span></font></td>\n  </tr>\n  <tr>\n    <td >\n    <p >&nbsp;</td>\n  </tr>\n</table>\n\n<table CELLSPACING=\"3\" CELLPADDING=\"3\"  border=\"1\"  >\n  <tr>\n    <td  >\n    <div align=\"center\">\n      <center>\n      <table  border=\"1\" border cellspacing=\"1\" >\n        <tr >\n          <td align=\"middle\"  ><b>\n          <font  size=\"2\">Jornada</font></b></td>\n          <td align=\"middle\"  >\n          <font  size=\"2\"><b>Puntos</b></font></td>\n          <td align=\"middle\"  >\n          <font  size=\"2\"><b>Fecha</b></font></td>\n          <td align=\"middle\"  colSpan=\"3\" >\n          <p class=\"resultado2\"><font  size=\"2\"><b>Partido</b></font></td>\n        </tr>\n        <tr>\n          <td align=\"middle\"  ><b>\n          <font  size=\"2\">1</font></b></td>\n          <td align=\"middle\"  >\n          </td>\n          <td align=\"middle\"  ></td>\n          <td onmouseover=\"this.style.backgroundColor=\'yellow\'\" onmouseout=\"this.style.backgroundColor=\'\'\" align=\"right\"  >\n          </td>\n          <td align=\"middle\"  >\n          </td>\n          <td onmouseover=\"this.style.backgroundColor=\'yellow\'\" onmouseout=\"this.style.backgroundColor=\'\'\" align=\"left\"  >\n          </td>\n        </tr>\n        <tr>\n          <td align=\"middle\"  ><b>\n          <font  size=\"2\">2</font></b></td>\n          <td align=\"middle\"  >\n          &nbsp;</td>\n          <td align=\"middle\"  >&nbsp;</td>\n          <td onmouseover=\"this.style.backgroundColor=\'yellow\'\" onmouseout=\"this.style.backgroundColor=\'\'\" align